import { useEffect, useRef } from "react";
import { Renderer, Camera, Transform, Plane, Program, Mesh, Texture, Vec2 } from "ogl";

const vertex = `
  attribute vec3 position;
  attribute vec2 uv;
  uniform mat4 modelViewMatrix;
  uniform mat4 projectionMatrix;
  uniform float uBendAmount;
  varying vec2 vUv;
  void main() {
    vUv = uv;
    vec3 pos = position;
    float dist = length(pos.xy);
    pos.z -= pow(dist * uBendAmount, 2.0) * 0.3;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
  }
`;

const fragment = `
  precision highp float;
  uniform sampler2D tMap;
  uniform float uOpacity;
  varying vec2 vUv;
  void main() {
    vec4 color = texture2D(tMap, vUv);
    gl_FragColor = vec4(color.rgb, color.a * uOpacity);
  }
`;

function lerp(a, b, t) { return a + (t - a) * b; }

export default function CircularGallery({ items, bend = 1, borderRadius = 0.05, scrollSpeed = 2, scrollEase = 0.05 }) {
  const containerRef = useRef(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const renderer = new Renderer({ alpha: true, antialias: true });
    const gl = renderer.gl;
    gl.clearColor(0, 0, 0, 0);
    container.appendChild(gl.canvas);

    const camera = new Camera(gl, { fov: 35 });
    camera.position.z = 5;

    const scene = new Transform();
    const meshes = [];
    let targetX = 0;
    let currentX = 0;
    let isDragging = false;
    let startX = 0;
    let startScroll = 0;

    const resize = () => {
      renderer.setSize(container.offsetWidth, container.offsetHeight);
      camera.perspective({ aspect: gl.canvas.width / gl.canvas.height });
      meshes.forEach((m, i) => {
        const spacing = 2.2;
        m.position.x = (i - (meshes.length - 1) / 2) * spacing;
      });
    };

    items.forEach((item, i) => {
      const geometry = new Plane(gl, { width: 1.8, height: 1.2, widthSegments: 20, heightSegments: 20 });
      const texture = new Texture(gl, { generateMipmaps: false });
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = item.image;
      img.onload = () => { texture.image = img; };

      const program = new Program(gl, {
        vertex,
        fragment,
        uniforms: {
          tMap: { value: texture },
          uBendAmount: { value: bend * 0.15 },
          uOpacity: { value: 1.0 },
        },
        transparent: true,
      });

      const mesh = new Mesh(gl, { geometry, program });
      const spacing = 2.2;
      mesh.position.x = (i - (items.length - 1) / 2) * spacing;
      mesh.setParent(scene);
      meshes.push(mesh);
    });

    // Label overlays
    const labels = items.map((item, i) => {
      const div = document.createElement("div");
      div.style.cssText = `
        position: absolute;
        bottom: 12px;
        left: 0; right: 0;
        text-align: center;
        color: white;
        font-family: 'Playfair Display', serif;
        font-size: 0.85rem;
        font-weight: 600;
        pointer-events: none;
        text-shadow: 0 2px 8px rgba(0,0,0,0.6);
        padding: 0 8px;
        opacity: 0;
        transition: opacity 0.3s;
      `;
      div.innerHTML = `<div>${item.org}</div><div style="font-family:DM Sans,sans-serif;font-size:0.7rem;font-weight:400;opacity:0.85;margin-top:2px">${item.roles.join(" · ")}</div>`;
      container.appendChild(div);
      return div;
    });

    const onDown = (e) => {
      isDragging = true;
      startX = e.clientX ?? e.touches?.[0]?.clientX;
      startScroll = targetX;
    };
    const onMove = (e) => {
      if (!isDragging) return;
      const x = e.clientX ?? e.touches?.[0]?.clientX;
      targetX = startScroll + (x - startX) * 0.01 * scrollSpeed;
    };
    const onUp = () => { isDragging = false; };
    const onWheel = (e) => { targetX -= e.deltaY * 0.003 * scrollSpeed; };

    container.addEventListener("mousedown", onDown);
    container.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    container.addEventListener("touchstart", onDown);
    container.addEventListener("touchmove", onMove);
    window.addEventListener("touchend", onUp);
    container.addEventListener("wheel", onWheel, { passive: true });

    let raf;
    const animate = () => {
      raf = requestAnimationFrame(animate);
      currentX = lerp(currentX, targetX, scrollEase + 0.05);

      const spacing = 2.2;
      const total = items.length * spacing;

      meshes.forEach((mesh, i) => {
        const baseX = (i - (items.length - 1) / 2) * spacing;
        mesh.position.x = baseX + currentX;

        // Infinite wrap
        if (mesh.position.x > total / 2) mesh.position.x -= total;
        if (mesh.position.x < -total / 2) mesh.position.x += total;

        // Project to screen for label positioning
        const projected = new Vec2();
        const w = container.offsetWidth;
        const h = container.offsetHeight;
        const screenX = (mesh.position.x / 5) * (w / 2) + w / 2;
        const label = labels[i];
        if (label) {
          label.style.left = `${screenX - 120}px`;
          label.style.width = "240px";
          label.style.bottom = `${h / 2 - 120}px`;
          const dist = Math.abs(mesh.position.x);
          label.style.opacity = dist < 1.5 ? String(1 - dist / 1.5) : "0";
        }
      });

      renderer.render({ scene, camera });
    };

    resize();
    window.addEventListener("resize", resize);
    animate();

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
      window.removeEventListener("mouseup", onUp);
      window.removeEventListener("touchend", onUp);
      container.removeEventListener("mousedown", onDown);
      container.removeEventListener("mousemove", onMove);
      container.removeEventListener("touchstart", onDown);
      container.removeEventListener("touchmove", onMove);
      container.removeEventListener("wheel", onWheel);
      labels.forEach(l => l.remove());
      if (gl.canvas.parentNode) gl.canvas.parentNode.removeChild(gl.canvas);
    };
  }, [items, bend, scrollSpeed, scrollEase]);

  return (
    <div
      ref={containerRef}
      style={{ width: "100%", height: "500px", position: "relative", cursor: "grab", overflow: "hidden" }}
    />
  );
}
